import streamlit as stimport plotly.graph_objects as goimport pandas as pdimport numpy as npfrom utils.data_utils import load_scoring, get_risk_colordef compute_lift_df(y_true, y_prob, n_bins=50):    df = pd.DataFrame({"y_true": y_true, "y_prob": y_prob})    df = df.sort_values("y_prob", ascending=False).reset_index(drop=True)    df["decile"] = pd.qcut(df.index, n_bins, labels=False, duplicates="drop")    total_pos = df["y_true"].sum()    total_n = len(df)    rows = []    for d in range(n_bins):        sub = df[df["decile"] <= d]        pct_pop = len(sub) / total_n * 100        pct_pos = sub["y_true"].sum() / max(total_pos, 1) * 100        rate_m = sub["y_true"].mean() if len(sub) > 0 else 0        lift = rate_m / max(df["y_true"].mean(), 1e-6)        rows.append({"pct_pop": pct_pop, "gains": pct_pos, "lift": lift})    return pd.DataFrame(rows)def render():    st.markdown("""    <div class='page-header'>        <h1>🚨 Priorisation CRM</h1>        <p>Identifiez les vols à traiter en priorité</p>    </div>""", unsafe_allow_html=True)    df_score = load_scoring()    lc = dict(plot_bgcolor="rgba(0,0,0,0)", paper_bgcolor="rgba(0,0,0,0)", font_color="#F0F4F8")    if df_score.empty:        st.warning("⚠️ scoring_crm_output.csv non trouvé. Lancez d'abord le pipeline ML de crm.py.")        st.info("Commande : générez scoring_crm_output.csv depuis le notebook crm.py, puis placez-le dans data/")        return    cf1, cf2, _ = st.columns(3)    with cf1:        risk_filt = st.multiselect("Niveau", ["🔴 Critique", "🟠 Élevé", "🟡 Modéré", "🟢 Faible"],                                   default=["🔴 Critique", "🟠 Élevé"])    with cf2:        pct_t = st.slider("% vols à cibler", 5, 50, 20)    if "RISK_LEVEL" not in df_score.columns:        df_score["RISK_LEVEL"] = pd.cut(            df_score["PROBA_RETARD"], bins=[0, 0.25, 0.50, 0.75, 1.0],            labels=["🟢 Faible", "🟡 Modéré", "🟠 Élevé", "🔴 Critique"], include_lowest=True        )    df_filt = df_score[df_score["RISK_LEVEL"].astype(str).isin(risk_filt)].copy()    n_target = max(1, int(len(df_score) * pct_t / 100))    df_top = df_score.head(n_target)    if "RETARD_BIN" in df_score.columns:        total_r = df_score["RETARD_BIN"].sum()        ret_cap = df_top["RETARD_BIN"].sum()        lift_val = (ret_cap / n_target) / max(df_score["RETARD_BIN"].mean(), 1e-6)        k1, k2, k3, k4 = st.columns(4)        with k1: st.metric("🎯 Vols ciblés", f"{n_target:,}", f"{pct_t}%")        with k2: st.metric("✅ Retards capturés", f"{ret_cap:,}", f"{ret_cap / max(total_r, 1) * 100:.1f}%")        with k3: st.metric("📈 Lift", f"{lift_val:.2f}x")        with k4: st.metric("💡 Économie ressources", f"{(1 - n_target / len(df_score)) * 100:.0f}%")    st.markdown("---")    if "RETARD_BIN" in df_score.columns:        ld = compute_lift_df(df_score["RETARD_BIN"].values, df_score["PROBA_RETARD"].values)        cl, cg = st.columns(2)        with cl:            fig = go.Figure()            fig.add_trace(go.Scatter(x=ld["pct_pop"], y=ld["lift"], mode="lines",                                     line=dict(color="#E94560", width=3), fill="tozeroy",                                     fillcolor="rgba(233,69,96,0.1)", name="Modèle"))            fig.add_hline(y=1, line_dash="dash", line_color="#6B7280", annotation_text="Aléatoire")            fig.add_vline(x=pct_t, line_dash="dot", line_color="#F39C12",                          annotation_text=f"{pct_t}%")            fig.update_layout(**lc, title="📈 Courbe de Lift",                              xaxis_title="% vols ciblés", yaxis_title="Lift")            st.plotly_chart(fig, use_container_width=True)        with cg:            fig2 = go.Figure()            fig2.add_trace(go.Scatter(x=[0, 100], y=[0, 100], mode="lines",                                      line=dict(color="#6B7280", dash="dash"), name="Aléatoire"))            fig2.add_trace(go.Scatter(x=ld["pct_pop"], y=ld["gains"], mode="lines",                                      line=dict(color="#2ECC71", width=3), fill="tozeroy",                                      fillcolor="rgba(46,204,113,0.1)", name="Modèle"))            fig2.add_vline(x=pct_t, line_dash="dot", line_color="#F39C12")            row_t = ld[ld["pct_pop"] <= pct_t].iloc[-1]            fig2.add_annotation(x=pct_t, y=row_t["gains"],                                text=f"{row_t['gains']:.1f}%\ncapturés",                                showarrow=True, arrowhead=2,                                font=dict(color="#F39C12", size=11),                                bgcolor="rgba(17,24,39,0.8)")            fig2.update_layout(**lc, title="🎯 Gains Cumulés",                               xaxis_title="% vols ciblés", yaxis_title="% retards capturés")            st.plotly_chart(fig2, use_container_width=True)    st.markdown(f"### 📋 Vols prioritaires — Top {min(50, len(df_filt))}")    disp_cols = [c for c in ["PROBA_RETARD", "RISK_LEVEL", "AP_DEP", "AP_ARR",                              "NOM_COMPAGNIE", "COMPAGNIE", "DATE", "RETARD_BIN"]                 if c in df_filt.columns]    df_d = df_filt[disp_cols].head(50).copy()    if "PROBA_RETARD" in df_d.columns:        df_d["PROBA_RETARD"] = (df_d["PROBA_RETARD"] * 100).round(1).astype(str) + "%"    def color_risk(val):        c = {"🔴 Critique": "#E74C3C", "🟠 Élevé": "#E67E22",             "🟡 Modéré": "#F39C12", "🟢 Faible": "#2ECC71"}        return f"color:{c.get(str(val), 'white')};font-weight:600"    if "RISK_LEVEL" in df_d.columns:        # Correction : applymap -> map (pandas >= 2.1.0)        styled_df = df_d.style.map(color_risk, subset=["RISK_LEVEL"])        st.dataframe(styled_df, use_container_width=True, height=400)    else:        st.dataframe(df_d, use_container_width=True, height=400)